```cpp
#include <Arduino.h>

#include <SPI.h>
#include <Adafruit_ST7735.h>
#include <Adafruit_GFX.h>

int gState = 0;
int gLastState = (-1);
int gAnimFrame = 0;
int gMuted = 0;
int gBtnFlag = 0;
unsigned long gSolenoidEnd = 0;

Adafruit_ST7735 tft = Adafruit_ST7735(10, 9, 7, 6, 8);

void setup() {
  Serial.begin(115200);
  tft.initR(INITR_BLACKTAB);
  // 如果显示异常，可尝试以下初始化参数：
  // tft.initR(INITR_REDTAB);
  // tft.initR(INITR_GREENTAB);
  // tft.initR(INITR_144GREENTAB);

  tft.setRotation(1);
  tft.fillScreen(tft.color565(0, 0, 0));
  tft.setTextSize(2);
  tft.setTextColor(ST77XX_WHITE);
  tft.setCursor(5 , 20 );
  tft.print("Claude");
  tft.setCursor(25 , 30 );
  tft.print("Monitor");
  delay(1500);
  pinMode(3, OUTPUT);
  digitalWrite(3, LOW);
  pinMode(4, OUTPUT);
  pinMode(2, INPUT_PULLUP);
  attachInterrupt(digitalPinToInterrupt(2), onButton, FALLING);

}

void loop() {

  if (Serial.available() >= 1) {
    String s = Serial.readStringUntil('
    '); s.trim();
    if(s == "idle")      gState = 0;
    else if(s == "thinking") gState = 1;
    else if(s == "coding")   gState = 2;
    else if(s == "done")     gState = 3;
    else if(s == "permission") gState = 4;
  }
  if (gBtnFlag == 1) {
    gBtnFlag = 0;
    delay(40);
    if (digitalRead(2) == LOW) {
      unsigned long start = millis();
      while(digitalRead(2) == LOW && millis() - start < 1200) { delay(20); }
      unsigned long held = millis() - start;
      if(held > 700) {
        gMuted = !gMuted;
        if(gMuted) { Serial.println("muted"); }
        else { tone(4, 800, 100); Serial.println("unmuted"); }
      } else {
        Serial.println("btn");
        tone(4, 1000, 50);
      }
    }
  }
  if (gState != gLastState) {
    gLastState = gState;
    gAnimFrame = 0;
    tft.fillScreen(tft.color565(0, 0, 0));
    if(gState == 3) { gSolenoidEnd = millis() + 300; digitalWrite(3, HIGH); }
    if(gState == 4) { gSolenoidEnd = millis() + 200; digitalWrite(3, HIGH); }
  }
  if (gState == 0) {
    static unsigned long idleT = 0;
    if(millis() - idleT > 600) {
      idleT = millis(); gAnimFrame = (gAnimFrame + 1) % 4;
      tft.fillScreen(ST77XX_BLACK);
      tft.setTextSize(3); tft.setCursor(25, 20); tft.setTextColor(ST77XX_WHITE); tft.print("Z");
      if(gAnimFrame >= 1) tft.print("z");
      if(gAnimFrame >= 2) tft.print("z");
      if(gAnimFrame == 3) tft.print(".");
      tft.setTextSize(1); tft.setCursor(10, 60); tft.setTextColor(ST77XX_CYAN); tft.print("[WORK IS OVER]");
      if(!gMuted && gAnimFrame == 0) tone(4, 440, 30);
    }
  }
  if (gState == 1) {
    static unsigned long thinkT = 0;
    if(millis() - thinkT > 400) {
      thinkT = millis(); gAnimFrame = (gAnimFrame + 1) % 6;
      tft.fillScreen(ST77XX_BLACK); tft.setTextSize(2); tft.setCursor(10, 5); tft.setTextColor(ST77XX_YELLOW); tft.print("Thinking");
      for(int i = 0; i < gAnimFrame; i++) { tft.drawCircle(80, 50, 8 + i * 6, ST77XX_YELLOW); }
      if(!gMuted) tone(4, 600 + gAnimFrame * 80, 30);
    }
  }
  if (gState == 2) {
    static unsigned long codeT = 0;
    if(millis() - codeT > 250) {
      codeT = millis(); gAnimFrame = (gAnimFrame + 1) % 8;
      tft.fillScreen(ST77XX_BLACK); tft.setTextSize(1); tft.setTextColor(ST77XX_GREEN);
      for(int i = 0; i < 7; i++) {
        tft.setCursor(5, 5 + i * 10);
        tft.print(((gAnimFrame + i) % 4 == 0) ? "> " : "  ");
        tft.print(i); tft.print(" line()");
      }
      if(!gMuted && gAnimFrame == 0) tone(4, 1000, 20);
    }
  }
  if (gState == 3) {
    static unsigned long doneT = 0;
    if(millis() - doneT > 500) {
      doneT = millis(); gAnimFrame = (gAnimFrame + 1) % 3;
      tft.fillScreen(ST77XX_BLACK); tft.setTextSize(3); tft.setTextColor(ST77XX_GREEN); tft.setCursor(30, 10); tft.print("OK!");
      if(gAnimFrame == 1) tft.fillCircle(80, 50, 15, ST77XX_GREEN);
      else tft.drawCircle(80, 50, 15, ST77XX_GREEN);
      if(!gMuted) tone(4, 1500, 80);
    }
  }
  if (gState == 4) {
    static unsigned long permT = 0;
    if(millis() - permT > 300) {
      permT = millis(); gAnimFrame = !gAnimFrame;
      tft.fillScreen(gAnimFrame ? ST77XX_RED : ST77XX_BLACK);
      tft.setTextSize(2); tft.setTextColor(ST77XX_WHITE);
      tft.setCursor(5, 15); tft.print("PRESS");
      tft.setCursor(10, 45); tft.print("BUTTON");
      if(!gMuted) tone(4, gAnimFrame ? 2000 : 800, 100);
      gSolenoidEnd = millis() + 150;
      digitalWrite(3, gAnimFrame);
    }
  }
  if (millis() >= gSolenoidEnd) {
    digitalWrite(3, LOW);
  }
  delay(30);

}
```

